import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import * as stylex from "@stylexjs/stylex";
import { borderRadiusStyles } from "@/utils/layouts.styles";
import type { PropsWithStylex } from "@/utils/stylex.utils";
import { Spinner } from "../Spinner/spinner";
import {
	buttonSizes,
	buttonStyles,
	buttonVariantStyles,
} from "./button.styles";

type _BaseUIButtonProps = PropsWithStylex<useRender.ComponentProps<"button">>;

type ButtonProps = PropsWithStylex<_BaseUIButtonProps> & {
	variant?: keyof typeof buttonVariantStyles;
	size?: keyof typeof buttonSizes;
	disabled?: boolean;
	loading?: boolean;
	radius?: keyof typeof borderRadiusStyles;
	fullWidth?: boolean;
};

function Button({
	children,
	variant = "primary",
	size = "medium",
	disabled: disabledProp,
	loading,
	type = "button",
	fullWidth,
	radius,
	render,
	style,
	...props
}: ButtonProps) {
	const isDisabled: boolean = Boolean(loading || disabledProp);
	const typeValue = render ? undefined : (type ?? "button");

	const defaultProps = {
		...props,
		children: (
			<>
				{children}
				{loading && (
					<Spinner
						style={buttonStyles.spinner}
						data-slot="button-loading-indicator"
					/>
				)}
			</>
		),
		...stylex.props(
			buttonStyles.base,
			fullWidth && buttonStyles.fullWidth,
			buttonVariantStyles[variant],
			buttonSizes[size],
			radius && borderRadiusStyles[radius],
			style,
		),
		"aria-disabled": loading || undefined,
		"data-loading": loading ? "" : undefined,
		"data-slot": "button",
		disabled: isDisabled,
		type: typeValue,
	};
	return useRender({
		defaultTagName: "button",
		props: mergeProps<"button">(defaultProps, props),
		render,
	});
}

export { Button };
export type { ButtonProps };

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import { fontSize, fonts, spacing } from "@/lib/theme/tokens.stylex";

export const buttonSizes = stylex.create({
	xsmall: {
		paddingTop: spacing.xxsmall,
		paddingBottom: spacing.xxsmall,
		paddingLeft: spacing.xsmall,
		paddingRight: spacing.xsmall,
		fontSize: fontSize.small,
	},
	small: {
		paddingTop: spacing.xsmall,
		paddingBottom: spacing.xsmall,
		paddingLeft: spacing.small,
		paddingRight: spacing.small,
	},
	icon: {
		paddingTop: spacing.xsmall,
		paddingBottom: spacing.xsmall,
		paddingLeft: spacing.xsmall,
		paddingRight: spacing.xsmall,
	},
	medium: {
		paddingTop: spacing.small,
		paddingBottom: spacing.small,
		paddingLeft: spacing.medium,
		paddingRight: spacing.medium,
	},
	large: {
		paddingTop: spacing.medium,
		paddingBottom: spacing.medium,
		paddingLeft: spacing.large,
		paddingRight: spacing.large,
		fontSize: fontSize.large,
	},
});

export const buttonVariantStyles = stylex.create({
	primary: {
		backgroundColor: theme.primary,
		borderColor: theme.primary,
		color: theme.contentOnPrimary,
		":hover:not(:disabled)": {
			backgroundColor: theme.primarySubtle,
			borderColor: theme.primarySubtle,
		},
	},
	secondary: {
		backgroundColor: "transparent",
		borderColor: theme.border,
		color: theme.contentAccent,
		":hover:not(:disabled)": {
			backgroundColor: theme.backgroundSubtle,
			borderColor: theme.borderStrong,
			color: theme.contentPrimary,
		},
	},
	ghost: {
		backgroundColor: "transparent",
		borderColor: "transparent",
		color: theme.contentAccent,
		":hover:not(:disabled)": {
			backgroundColor: theme.backgroundSubtle,
		},
	},
	outline: {
		backgroundColor: "transparent",
		borderColor: theme.border,
		color: theme.contentPrimary,
		":hover:not(:disabled)": {
			backgroundColor: theme.backgroundSubtle,
			borderColor: theme.borderStrong,
		},
	},
	"outline-dashed": {
		borderStyle: "dashed",
		backgroundColor: "transparent",
		borderColor: theme.border,
		color: theme.contentPrimary,
		":hover:not(:disabled)": {
			backgroundColor: theme.backgroundSubtle,
			borderColor: theme.borderStrong,
		},
	},
	soft: {
		backgroundColor: theme.backgroundSubtle,
		borderColor: "transparent",
		color: theme.contentPrimary,
		":hover:not(:disabled)": {
			backgroundColor: theme.surfaceRaised,
		},
	},
	link: {
		backgroundColor: "transparent",
		borderColor: "transparent",
		color: theme.contentAccent,
		paddingLeft: 0,
		paddingRight: 0,
		":hover:not(:disabled)": {
			textDecoration: "underline",
		},
	},
	danger: {
		backgroundColor: theme.sentimentNegative,
		borderColor: theme.sentimentNegative,
		color: theme.contentOnPrimary,
		":hover:not(:disabled)": {
			backgroundColor: theme.sentimentNegativeSubtle,
			borderColor: theme.sentimentNegativeSubtle,
			color: theme.sentimentNegative,
		},
	},
	success: {
		backgroundColor: theme.sentimentPositive,
		borderColor: theme.sentimentPositive,
		color: theme.contentOnPrimary,
		":hover:not(:disabled)": {
			backgroundColor: theme.sentimentPositiveSubtle,
			borderColor: theme.sentimentPositiveSubtle,
			color: theme.sentimentPositive,
		},
	},
});

export const buttonStyles = stylex.create({
	base: {
		display: "inline-flex",
		alignItems: "center",
		justifyContent: "center",
		gap: spacing.small,
		borderStyle: "solid",
		borderWidth: 1,
		borderRadius: theme.borderRadius,
		cursor: "pointer",
		fontWeight: 500,
		height: "fit-content",
		fontSize: theme.fontSize,
		fontFamily: fonts.display,
		textDecoration: "none",
		transition: "all 0.2s ease",
		":disabled": {
			opacity: 0.4,
			cursor: "not-allowed",
		},
	},

	spinner: {
		position: "absolute",
		pointerEvents: "none",
	},
	fullWidth: {
		width: "100%",
	},
});
